import {BeSkill, Options} from '@be/be-framework';
import jibo = require('jibo');

import ErrorDisplay, {JiboErrorData} from './ErrorDisplay';
import WiFi from './WiFi';

import AboutSkill, {AboutPage} from './subskills/AboutSkill';
import BatterySkill from './subskills/BatterySkill';
import ErrorSkill from './subskills/ErrorSkill';
import MenuSkill from './subskills/MenuSkill';
import ShutdownSkill from './subskills/ShutdownSkill';
import ShutdownAnimationSkill from './subskills/ShutdownAnimationSkill';
import UpdatesSkill from './subskills/UpdatesSkill';
import VolumeSkill from './subskills/VolumeSkill';
import WifiSkill from './subskills/WifiSkill';
import WipeSkill from './subskills/WipeSkill';


import SubSkill from './subskills/SubSkill';
import Analytics from './analytics/Analytics';
import PowerAnalytics from './analytics/PowerAnalytics';
import { AsyncCallback } from '@be/be-framework/lib/dts/BeSkill';

type SkillOptions = {fromTouch?: boolean, nlu?: {intent?: string, entities: {skill: string, errorId: string}}};

type SubSkills = {
    about: { Class: typeof AboutSkill },
    battery: { Class: typeof BatterySkill },
    error: { Class: typeof ErrorSkill, uninterruptible: boolean, refreshable: boolean },
    menu: { Class: typeof MenuSkill },
    shutDown: { Class: typeof ShutdownSkill },
    shutdownAnimation: { Class: typeof ShutdownAnimationSkill, uninterruptible: boolean },
    updates: { Class: typeof UpdatesSkill },
    volumeQuery: { Class: typeof VolumeSkill },
    wifiStatus: { Class: typeof WifiSkill },
    wipe: { Class: typeof WipeSkill, uninterruptible: boolean }
};

export default class Settings extends BeSkill {

    static BeSkill = BeSkill;
    static AboutPage = AboutPage;

    public SUB_SKILLZ: SubSkills = {
        about: { Class: AboutSkill },
        battery: { Class: BatterySkill },
        error: { Class: ErrorSkill, uninterruptible: true, refreshable: true },
        menu: { Class: MenuSkill },
        shutDown: { Class: ShutdownSkill },
        shutdownAnimation: { Class: ShutdownAnimationSkill, uninterruptible: true },
        updates: { Class: UpdatesSkill },
        volumeQuery: { Class: VolumeSkill },
        wifiStatus: { Class: WifiSkill },
        wipe: { Class: WipeSkill, uninterruptible: true }
    };

    public root: jibo.kb.Node;

    public errorMetaData: {[code: string]: JiboErrorData};
    public currentErrorCode: string;

    public currentIntent: string;
    public currentSkill: SubSkill;

    public previousSkillName: string;
    public previousSkillOptions: SkillOptions;

    public _analytics: Analytics;

    private _globalIgnoreState: boolean;

    /**
     * Settings skill constructor
     * @constructor
     * @param {String} [assetPack=''] The asset pack if loading from Be
     */
    constructor(assetPack: Options) {
        super(assetPack);
        this.root = null;
        this.currentIntent = null;
        this.panelClosed = this.panelClosed.bind(this);

        this.errorMetaData = null; //cached list of errors from KB
        this.previousSkillName = null;
        this.previousSkillOptions = null;
        this.currentErrorCode = null;

        this._globalIgnoreState = false;
        this.globalDoNothing = this.globalDoNothing.bind(this);

        this._analytics = new Analytics(this);
        PowerAnalytics.init();
    }

    public postInit(callback: AsyncCallback): void {
        let errorKbm = jibo.kb.createModel('/error-codes');
        errorKbm.loadRoot((err, root) => {
            if (err) {
                this.log.error('error loading error root from KB', err);
            }
            this.errorMetaData = root.data.errorCodes;

            let kbm = jibo.kb.createModel('/settings');
            kbm.loadRoot((err, root) => {
                if (err) {
                    this.log.error('error loading settings root from KB', err);
                }
                this.root = root;

                //notify server that we're connected so SSID and other info can be displayed on  mobile
                (jibo as any).wifi.getCurrentNetwork((err, net) => {
                    if (err || !net || !net.ssid) {
                        this.log.warn('Not connected to WiFi at Be startup. Error: ', err);
                    }
                    else {
                        WiFi.notifyServer(net.ssid, this.log);
                    }
                    callback();
                });
            });
        });
    }
    public preload(callback) {
        callback();
    }

    /**
     * Start the skill
     * @method open
     */
    public open(data: SkillOptions, refresh: boolean, previousSkillName: string, previousSkillOptions: SkillOptions): void {
        let intent = 'menu';//default intent
        let fromTouch = false;//for analytics
        if (data) {
            if (data.nlu) {
                if (data.nlu.entities && data.nlu.entities.errorId) {
                    intent = 'error';
                    this.currentErrorCode = data.nlu.entities.errorId;
                    if (this.currentIntent === 'error' && (this.currentSkill as ErrorSkill).errorDisplay && (this.currentSkill as ErrorSkill).errorDisplay.wipeSkill) {
                        //do nothing, this is probably expected
                        this.log.info(`Got ${this.currentErrorCode} error while displaying secret Wipe menu. This is fine.`);
                    }
                    else if (this.errorMetaData[this.currentErrorCode].tapAction === 'wifi' && (this.currentIntent === 'wifiStatus' ||
                        (this.currentIntent === 'error' && (this.currentSkill as ErrorSkill).errorDisplay && (this.currentSkill as ErrorSkill).errorDisplay.wifiSkill))) {
                        //do nothing, this is probably expected
                        this.log.info(`Got ${this.currentErrorCode} error while in WiFi settings. This is fine.`);
                        return;
                    }
                }
                else if (data.nlu.intent) {
                    intent = data.nlu.intent;
                }
            }
            fromTouch = !!data.fromTouch;
        }

        if (refresh) {
            if (this.currentIntent === intent && !this.SUB_SKILLZ[intent].refreshable) {
                this.log.info(`Ignoring skill refresh because ${this.currentIntent} is already active.`);
                // emit No Global to tell any menu mims that were open
                // to keep listening, since relaunches interrupt them.
                jibo.globalEvents.shared.nonInterruptingGlobal.emit();
                return;
            }
            if (this.currentSkill && this.currentSkill.intent === 'menu') {
                (this.currentSkill as MenuSkill).cleanup();
                this.openPanel(intent, fromTouch, previousSkillName, previousSkillOptions);
            }
            else {
                this.cleanupSubSkill(() => {
                    this.openPanel(intent, fromTouch, previousSkillName, previousSkillOptions);
                });
            }
        }
        else {
            this.openPanel(intent, fromTouch, previousSkillName, previousSkillOptions);
        }
    }

    /**
     * Stop and unload the skill
     * @method close
     */
    public close(done: AsyncCallback): void {
        this.previousSkillName = null;
        this.previousSkillOptions = null;

        this.currentIntent = null;
        this.cleanupSubSkill(done);
    }

    /**
     * destroy - because Be never destroys skills, this is only used to cleanup between unit tests
     */
    public destroy(done: () => {}): void {
        done();
    }

    /**
     * will redirect to the previous skill with the previous intent
     * @method goBack
     */
    public goBack(): void {
        if (this.previousSkillName === '@be/settings' && this.previousSkillOptions.nlu && this.previousSkillOptions.nlu.entities && this.previousSkillOptions.nlu.entities.errorId) {
            let options: SkillOptions = this.previousSkillOptions;//save ref for safety/paranoia
            jibo.errors.getCurrentErrorId((err, errorCode)=>{
                if (!err && errorCode) {
                    this.log.warn('trying to redirect from error skill to error skill. Succeed - An error is active: ', errorCode);
                    options.nlu.entities.errorId = errorCode;
                    this.redirect('@be/settings', options);
                }
                else {
                    this.log.warn('trying to redirect from error skill to error skill. Fail - No error active, go to Idle');
                    this.redirect('@be/idle', {});
                }
            });
        }
        else {
            this.redirect(this.previousSkillName || '@be/idle', this.previousSkillOptions || {});
        }
    }

    /**
     * will redirect to Idle unless there is an error that should be shown to users
     * @method goBack
     */
    public exit2Idle(): void {
        jibo.errors.getCurrentErrorId((err, errorCode)=>{
            if (!err && errorCode) {
                this.log.warn('trying to exit from error skill, but an error is still active: ', errorCode);
                let options: SkillOptions = {nlu: {entities: { skill: '@be/settings', errorId: errorCode }}};
                this.redirect('@be/settings', options);
            }
            else {
                this.redirect('@be/idle', {});
            }
        });
    }

    public ignoreGlobalStops(enable: boolean): void {
        if (this._globalIgnoreState === enable) { //only do this if we need to
            return;
        }
        this._globalIgnoreState = enable;
        if (enable) {
            jibo.globalEvents.touchStop.on(this.globalDoNothing);
            jibo.globalEvents.voiceStop.on(this.globalDoNothing);
        }
        else {
            jibo.globalEvents.touchStop.removeListener(this.globalDoNothing);
            jibo.globalEvents.voiceStop.removeListener(this.globalDoNothing);
        }
    }
    private globalDoNothing() {
        this.log.info(`ignoring global stop command in ${this.currentIntent} SubSkill.`);
        jibo.globalEvents.shared.nonInterruptingGlobal.emit();
    }

    private openPanel(intent: string, fromTouch: boolean, previousSkillName: string, previousSkillOptions: SkillOptions): void {
        this.previousSkillName = previousSkillName;
        this.previousSkillOptions = previousSkillOptions;
        this.currentIntent = intent;
        if (!this.SUB_SKILLZ[intent]) {
            this.log.warn(`no SubSkill for intent ${intent}`);
            this.exit();
            return;
        }
        this._isInterruptible = !this.SUB_SKILLZ[intent].uninterruptible;
        this.currentSkill = new this.SUB_SKILLZ[intent].Class(this, intent, this.panelClosed.bind(this), fromTouch);
    }

    private panelClosed(): void {
        this.currentSkill = null;
        if (this.previousSkillName === '@be/settings' && this.previousSkillOptions.nlu && this.previousSkillOptions.nlu.intent === 'menu') {
            //only 'go back' if we came from the settings menu
            this.log.info('Going back to settings Menu');
            this.goBack();
        }
        else {
            this.exit();
        }
    }

    private cleanupSubSkill(done: AsyncCallback) {
        if (this.currentSkill) {
            if (this.currentSkill.intent) {
                //not yet destroyed: do full interruption cleanup
                this.currentSkill.log.info('SubSkill killed before its time');
                this.currentSkill.stopAndDestroy((err) => {
                    if (err) {
                        this.log.warn('SubSkill closed with errors: ', err);
                    }
                    this.currentSkill = null;
                    done();
                });
            }
            else {
                //aready cleaned itself up, remove reference and GTFO!
                this.currentSkill = null;
                done();
            }
        }
        else {
            //cleaning up with no subskill active. this is totally fine.
            done();
        }
    }
}