import jibo = require('jibo');
import Settings from '../Settings';

import SubSkill from './SubSkill';
import WiFi from '../WiFi';

/**
 * WiFi Skill - Jibo needs this to live
 */
export default class WifiSkill extends SubSkill {

    private wifi: WiFi;

    constructor(skill: Settings, intent: string, onClose: Function, fromTouch?: boolean, fromError?:boolean) {
        super(skill, intent, onClose);

        this.wifi = new WiFi(this.skill, this.log, fromError || false);
        (this.wifi as any).analytics = this.skill._analytics;
        this.wifi.showWiFiMenu(() => {
            this.destroyThenClose();
        });
    }

    stopAndDestroy(done: Function) {
        this.destroy();
        jibo.face.views.changeView(
            { removeAll: true, leaveEmpty: true },
            () => {
                done();
            },
            () => {
                done('wifi view close failed');
            }
        );
    }

    destroy() {
        this.wifi.destroy();
        this.wifi = null;
        super.destroy();
    }
}
