import jibo = require('jibo');
import Settings from '../Settings';

import SubSkill from './SubSkill';
import VolumeView from '../views/VolumeView';

/**
 * Volume Skill - turn up!
 */
export default class VolumeSkill extends SubSkill {

    private view: VolumeView;

    constructor(skill: Settings, intent: string, onClose: Function, fromTouch:boolean) {
        super(skill, intent, onClose);

        this.skill._analytics.volumeOpened(fromTouch);
        jibo.face.views.creator.registerClass(VolumeView, 'VolumeView');
        this.view = jibo.face.views.createView('VolumeView', 'assets/volume/volumeView.json', false) as VolumeView;
        this.view.assetPack = this.assetPack;
        this.view.analytics = this.skill._analytics;
        this.view.once(jibo.face.views.CLOSED, this.destroyThenClose);
        jibo.face.views.changeView(
            {
                addView: this.view
            }
        );
    }

    stopAndDestroy(done: Function) {
        this.view.removeListener(jibo.face.views.CLOSED, this.destroyThenClose);
        jibo.face.views.changeView(
            { removeAll: true, leaveEmpty: true },
            () => {
                this.destroy();
                done();
            },
            () => {
                this.destroy();
                done('volume view close failed');
            }
        );
    }

    destroy() {
        jibo.face.views.creator.unregisterClass('VolumeView');
        this.view = null;
        super.destroy();
    }
}
