import jibo = require('jibo');

/*
 * WipeView - attempts backup prior to wiping; triggers error if unsuccessful; otherwise, sets mode to "oobe"
 *            if current mode is "normal" and reboots
 */
export default class WipeView extends jibo.rendering.gui.views.View {

    private log: any;//TODO: figure out actual type

    constructor(viewState) {
        super(viewState);
        this.log = null;
    }

    setLogger(log) {
        this.log = log;
    }

    run(skipBackup:boolean = false) {

        // start the chain of events
        Promise.resolve()
            .then(( /* backup before? */) => {
                if (skipBackup) {
                    return;
                }
                //now we either have an internet connection or are going to try to backup anyway
                return new Promise((resolve, reject) => {
                    this.log.info("Wipe - backing up...");
                    jibo.systemManager.backup((err) => {
                        if (err) {
                            this.log.error("Wipe - backup error:", err);
                        }

                        // always resolve here
                        resolve();
                    });
                });
            })
            .then((/* set mode, suspend loop, wipe, force logs, clear creds, clear wifi */) => {
                 // update label
                let label: jibo.face.views.Label = this.getComponentById("wipeLabel") as jibo.face.views.Label;
                label.text = "Wiping robot...";
                //if we were told to skip the backup, then tell the wipe util to skip web things
                //if there is no internet connection
                return jibo.utils.WipeUtil.run(this.log, skipBackup);
            })
            .then(( /* reboot */) => {
                return new Promise((resolve, reject) => {
                    // update label
                    let label: jibo.face.views.Label = this.getComponentById("wipeLabel") as jibo.face.views.Label;
                    label.text = "Rebooting...";

                    this.log.info("Wipe - rebooting! Bye.");
                    jibo.systemManager.reboot((err) => {
                        if (err) {
                            this.log.error("Wipe - reboot error: ", err);
                        }
                        resolve(); // always resolve at this point
                    });
                });
            })
            .catch((err) => {
                this.log.info("Wipe error: ", err);
                this.emit('wipeFail');
            });
    }
}
