import jibo = require('jibo');
import {BeSkill} from '@be/be-framework';

export default class PowerAnalytics {
    private static shutdownModality:'menu'|'hardware';

    public static init() {
        //any shutdown would be via physical hardware unless we go through shutdown skill
        this.shutdownModality = 'hardware';
        //set up listeners for when Jibo's power is plugged/unplugged
        jibo.system.events.pluggedIn.on(this.onPluggedIn);
        jibo.system.events.unplugged.on(this.onUnplugged);
    }
    
    public static shutdownViaMenu() {
        this.shutdownModality = 'menu';
    }
    
    public static shutdown() {
        BeSkill.plugins.analytics.skillEvent('Shutdown', { modality: this.shutdownModality });
    }
    
    public static lowBatteryError() {
        BeSkill.plugins.analytics.skillEvent('Battery Low');
    }
    
    private static onUnplugged() {
        BeSkill.plugins.analytics.skillEvent('Unplugged');
    }
    
    private static onPluggedIn() {
        BeSkill.plugins.analytics.skillEvent('Plugged In');
    }
}
