import jibo = require('jibo');
import Settings from '../Settings';

/**
 * SubSkill - Base Class for Settings subskills
 */
export default class SubSkill {

    public intent: string;//used for logging namespace and to verify whether or not SubSkill has been cleaned up
    protected skill: Settings;
    public log: typeof jibo.log;
    protected assetPack: string;
    protected onClose: Function;//what to do when this subskill is closed

    constructor(skill: Settings, intent: string, onClose: Function, fromTouch?:boolean) {
        this.skill = skill;
        this.assetPack = this.skill.assetPack;
        this.log = this.skill.log.createChild(intent);
        this.log.info('SubSkill Launched');
        this.intent = intent;
        this.onClose = onClose;
        this.destroyThenClose = this.destroyThenClose.bind(this);
    }

    /**
     * stopAndDestroy - public interface to interrupt and cleanup skill
     * Unless SubSkill implementation is super-basic, always override this.
     */
    public stopAndDestroy(done: Function) {
        this.log.warn(`you probably want to override stopAndDestroy() in the ${this.intent} SubSkill`);
        this.destroy();
        done();
    }

    /**
     * destroyThenClose - call this when your SubSkill has ended naturally (closed itself)
     *
     */
    protected destroyThenClose() {
        this.log.info('SubSkill died of natural causes');
        let onClose = this.onClose;
        this.destroy();
        onClose();
    }

    /**
     * destroy - synchronous cleanup for subskill, to be done after asynchronous cleanup has completed
     *
     */
    protected destroy() {
        this.assetPack = null;
        this.intent = null;
        this.onClose = null;
        this.skill = null;
    }
}
