"use strict";
import jibo = require('jibo');

let fs = require('fs');

class AboutPage {

    // load the about page and add it to the view
    // @params[Function<View>] doneLoadingCallback - the callback which triggers after the view is done loading
    // @return[View] - the view which has the about page
    static about(doneLoadingCallback:Function, log: typeof jibo.log): jibo.face.views.View {
        let view = jibo.face.views.createView('View', 'assets/about/aboutView.json');

        // this needs to be before we try to load the view because the view starts to tween-in on LOADED
        jibo.systemManager.getIdentity((err, identityData) => {
            if (err) {
                if (log) {
                    log.error('Failed to get identity ', err);
                }
            }
            view.on(jibo.face.views.LOADED, (loadedView) => {
                this._viewLoaded(loadedView, identityData, log);
                if (doneLoadingCallback) {
                    doneLoadingCallback(loadedView);
                }
            });
            jibo.face.views.addView(view);
        });

        return view;
    }

    // callback for when the view is loaded to set the positions of the elements
    // THIS IS INTENDED TO BE A PRIVATE METHOD - exposed here only for unit testing
    // @params[View] aboutView - the view which has been loaded
    // @params[Object] identityData - the object returned from the jibo.systemManager.getIdentity method
    //                  [String] name - the robot name
    //                  [String] serial_number - the robot serial number
    static _viewLoaded(aboutView: jibo.face.views.View, identityData?: jibo.systemManager.Identity, log?: typeof jibo.log): void {
        try {
            let serialNumber = aboutView.getComponentById('serialNumber') as jibo.rendering.gui.components.Label;
            let robotName = aboutView.getComponentById('robotName') as jibo.rendering.gui.components.Label;
            let releaseVersion = aboutView.getComponentById('releaseVersion') as jibo.rendering.gui.components.Label;
            if (!identityData) {
                identityData = {name: robotName.text, serial_number: serialNumber.text, wifi_mac:null};
            }
            robotName.text = identityData.name;
            serialNumber.text = identityData.serial_number;
            releaseVersion.text = `Release Version: ${jibo.versions.release}`;
        }
        catch(err) {
            if (log) {
                log.error('Failed to display name and number ', err);
            }
        }
    }

}
export default AboutPage;
