import jibo = require('jibo');
import Settings from '../Settings';

import SubSkill from './SubSkill';
import PowerAnalytics from '../analytics/PowerAnalytics';

/**
 * Shutdown Animation Skill - Play animation and hold pose when Jibo is shutting down
 */
export default class ShutdownAnimationSkill extends SubSkill {

    constructor(skill: Settings, intent: string, onClose: Function) {
        super(skill, intent, onClose);
        PowerAnalytics.shutdown();//track that Jibo was shut down
        jibo.analytics.flush();//send analytics ASAP
        jibo.expression.setAttentionMode(jibo.expression.AttentionMode.OFF);
        // This is disabling the expression service's shutdown pose that would normally
        // occur when Be shuts down and closes the Expression Service.
        jibo.expression.doCenterRobotOnDisconnect(false);
        this.playAnimation = this.playAnimation.bind(this);
        jibo.face.views.forceEyeView(
            this.playAnimation,
            null,
            null,
            null,
            this.playAnimation
        );
    }

    playAnimation(){
        jibo.embodied.speech.speak(`<anim cat='system-states' filter='shutdown' />.`);
    }
}
