import jibo = require('jibo');
import Settings from '../Settings';

import SubSkill from './SubSkill';
import AboutPage from '../AboutPage';
import TouchyTimeout from '../utils/TouchyTimeout';

export {AboutPage};

const TIMEOUT_TIME = 120000;//2 minute timeout

/**
 * About Skill - for legal stuff and secret dev mode
 */
export default class AboutSkill extends SubSkill {

    private view: jibo.face.views.View;
    private timeout: TouchyTimeout;

    constructor(skill: Settings, intent: string, onClose: Function) {
        super(skill, intent, onClose);

        this.view = AboutPage.about(null, this.log);
        this.view.once(jibo.face.views.CLOSED, this.destroyThenClose);
        this.timeout = new TouchyTimeout(
            ()=>{
                this.stopAndDestroy(this.onClose);
            },
            TIMEOUT_TIME
        );
    }

    stopAndDestroy(done: Function) {
        if(this.timeout){
            this.timeout.destroy()
            this.timeout = null;
        }
        this.view.removeListener(jibo.face.views.CLOSED, this.destroyThenClose);
        jibo.face.views.changeView(
            { removeAll: true, leaveEmpty: true },
            () => {
                this.destroy();
                done();
            },
            () => {
                this.destroy();
                done('about view close failed');
            }
        );
    }

    destroy() {
        if(this.timeout){
            this.timeout.destroy()
            this.timeout = null;
        }
        this.view = null;
        super.destroy();
    }
}
