import WipeView from './views/WipeView';
import PowerAnalytics from './analytics/PowerAnalytics';
import jibo = require('jibo');
import Settings from './Settings';
import WipeSkill from './subskills/WipeSkill';
import WifiSkill from './subskills/WifiSkill';

const PULSE_LENGTH = 2; //seconds to tween light ring between MIN_BRIGHTNESS and MAX_BRIGHTNESS
const MIN_BRIGHTNESS = 0.4; //Dimmest red value (0-MAX_BRIGHTNESS)
const MAX_BRIGHTNESS = 1; //brightest red value (MIN_BRIGHTNESS-1)
const ERROR_COLOR = [1, 0.0784313725490196, 0.07450980392156863]; //100% 'Error Red' as specified by Heather (0xFF1413)
const TAP_EVENT = 'errorScreenTapEvent';
const QUIET_HOURS_START = 22;
const QUIET_HOURS_END = 7;
const SECRET_SWIPES_REQUIRED = 5;
const LOW_BATTERY_ERROR = 'K4-Low_battery';

//TODO: maybe update and export the JiboErrorData in SSM code to be imported here?
export interface JiboErrorData {
    code: string;
    description: string;
    icon: string;
    message: string;
    platformCode?: string;
    priority: number;
    repeatTime: number;
    spokenPromptOnError: string;
    spokenPromptOnResolution: string;
    tapAction: string;
    title: string;
}

type TapText = {dismiss: string, index: string, none:string, reboot: string, shutdown: string, wifi: string, wipe: string};
type Asset = {id: string, src: string, type: string};
type ViewConfig = {viewConfig: {type: string, category: string, id: string, ignoreSwipeDown: boolean}, componentConfigs: ComponentConfig[]};
type ComponentConfig = {id: string, type: string, assets?: Asset[], position: {x: number, y: number}};

class ErrorDisplay {

    skill: Settings;
    log: typeof jibo.log;
    assetPack: string;
    errorMetaData: {[JiboErrorCode: string] : JiboErrorData};
    tapActions: {wifi: Function, dismiss: Function, index: Function, none: Function, reboot: Function, shutdown: Function, wipe: Function};
    errorCode: string;
    currentMessage: JiboErrorData;
    queuedError: string;
    doingPulse: boolean;
    fadingUp: boolean;
    brightness: number;
    silent: boolean;
    wifiSkill: WifiSkill;
    wipeSkill: WipeSkill;
    isHeadHeld: boolean;
    numOfSwipes: number;
    touchStartTime: number;
    attentionHandler: jibo.expression.AttentionHandle;
    currentView: jibo.face.views.View;

    constructor(skill: Settings, log: typeof jibo.log) {
        this.skill = skill;
        this.log = log;
        this.assetPack = skill.assetPack;
        this.errorMetaData = skill.errorMetaData; //cached KB data
        this.tapActions = {
            wifi: this.doWifi.bind(this), //open wifi panel
            dismiss: this.dismissError.bind(this), //exit to idle
            index: () => {
                jibo.expression.indexRobot();
            },
            none: null, //do nothing
            reboot: () => {
                jibo.systemManager.reboot((err) => {
                    if (this.skill && err) {
                        this.log.error('failed to reboot on tap from error skill.', err);
                    }
                });
            },
            shutdown: () => {
                jibo.systemManager.poweroff((err) => {
                    if (this.skill && err) {
                        this.log.error('failed to shutdown on tap from error skill.', err);
                    }
                });
            },
            wipe: this.doWipe.bind(this)
        };
        this.errorCode = null; //current errorCode being handled
        this.currentMessage = null;
        this.queuedError = null;

        //light pulse stuff:
        this.ringPulse = this.ringPulse.bind(this);
        this.doingPulse = false;
        this.fadingUp = true; //are we fading pulse up or down?
        this.brightness = 0;
        this.silent = false;

        //sub-subskill stuff
        this.wifiSkill = null;
        this.wipeSkill = null;

        //secret wipe code stuff
        this.isHeadHeld = false;
        this.numOfSwipes = 0;
        this.touchStartTime = 0;

        //exiting function used in callback
        this.onWifiExitedAfterSolved = this.onWifiExitedAfterSolved.bind(this);
        this.onHeadUpdate = this.onHeadUpdate.bind(this);
        jibo.timer.on('update', this.onHeadUpdate);
    }

    doError(errorCode: string): void {
        if (!this.skill) {
            return;
        }

        if (errorCode === LOW_BATTERY_ERROR) {
            PowerAnalytics.lowBatteryError();
        }

        //TODO: hopefully this will never happen ;-D
        this.currentMessage = {
            title: 'Error Error',
            message: 'Encountered an error when trying to display an error',
            tapAction: 'dismiss',
            icon: 'error',
            code: errorCode,
            spokenPromptOnError: null,
            spokenPromptOnResolution: null,
            description: null,
            platformCode: null,
            priority: null,
            repeatTime: null

        };
        this.currentMessage = this.errorMetaData[errorCode];

        jibo.errors.subscribeError(errorCode, this.onResolved.bind(this));
        let time = new Date().getHours(); // integer hour of day 0-23
        this.silent = time >= QUIET_HOURS_START || time < QUIET_HOURS_END;
        this.errorCode = errorCode;

        jibo.expression.pushAttentionMode(jibo.expression.AttentionMode.OFF).then((handle) => {
            this.attentionHandler = handle;
            if (!this.skill) {
                this.attentionHandler.release();
                return;
            }

            jibo.expression.centerRobot();

            jibo.loader.load('assets/errors/data.json', (err, result) => {
                if (!this.skill) {
                    return;
                }
                let icons: {[icon: string]: Asset} = result.icons;
                let tapText: TapText = result.tapText;
                jibo.loader.load('assets/errors/error.json', (err, result) => {
                    if (!this.skill) {
                        return;
                    }
                    let viewConfig: ViewConfig = result;
                    let icon = icons[this.currentMessage.icon] || icons['error']; //safety in case data is bad
                    viewConfig.componentConfigs[0].assets.push(icon);
                    this.currentView = jibo.face.views.createView('View', viewConfig, false);
                    jibo.face.views.changeView({
                            addView: this.currentView
                        },
                        () => { //on view opened (transition-in complete)
                            if (!this.skill) {
                                return;
                            }
                            //action must be added after view is opened
                            this.currentView.addAction(jibo.face.views.ActionData.CALLBACK, {callback: this.onSwipeUp.bind(this)}, false, false, jibo.face.views.GESTURE.SWIPE_UP);
                            this.doPulse(true);
                            if (!this.silent) {
                                if (this.currentMessage.spokenPromptOnError && this.currentMessage.spokenPromptOnError.length) {
                                    jibo.sound.play('error', () => {
                                        if (!this.skill) {
                                            return;
                                        }
                                        jibo.tts.speak(
                                            this.currentMessage.spokenPromptOnError, {
                                                mode: jibo.tts.TTSMode.SSML
                                            }
                                        );
                                    });
                                }
                                else {
                                    jibo.sound.play('error');
                                }
                            }
                        },
                        () => { //on view failed to open (interrupted usually)
                            if (!this.skill) {
                                return;
                            }
                            this.log.warn('view change interrupted or something like that');
                        },
                        () => { //on view loaded (about to transition in)
                            if (!this.skill) {
                                return;
                            }
                            let tapAction: Function = this.tapActions[this.currentMessage.tapAction];
                            if (tapAction) {
                                this.currentView.addAction('event', {
                                    event: TAP_EVENT
                                });
                                this.currentView.on(TAP_EVENT, tapAction);
                            }

                            (this.currentView.getComponentById('header') as jibo.face.views.Label).text = this.currentMessage.title;
                            (this.currentView.getComponentById('message') as jibo.face.views.Label).text = this.currentMessage.message;
                            (this.currentView.getComponentById('tap') as jibo.face.views.Label).text = tapText[this.currentMessage.tapAction];
                            (this.currentView.getComponentById('code') as jibo.face.views.Label).text = `Error ${this.currentMessage.code}`;
                        }
                    );
                });
            });
        });
    }

    onResolved(err: any, data: {nextErrorId: string, resolved: boolean}): void {
        if (!this.skill) {
            return;
        }
        if (err) {
            if (err.name === jibo.web.ErrorStatus.ABORTED) {
                this.log.info('current error display aborted: ', err);
            }
            else {
                this.log.warn('error resolved with error: ', err);
            }
            return;
        }
        this.log.info('error resolved: ', this.errorCode);
        if (this.queuedError) { //clear any previously-queued error
            this.queuedError = null;
        }
        this.doPulse(false);
        if (data && data.nextErrorId) {
            if (this.wifiSkill || this.wipeSkill) {
                this.log.info('got queued error while still in wifi settings - save for later');
                this.queuedError = data.nextErrorId;
            }
            else if (jibo.face.views.currentView && jibo.face.views.currentView.id == 'wipeView' && this.errorMetaData[data.nextErrorId].tapAction == 'wifi') {
                this.log.info('ignoring WiFi error because we are wiping the robot right now');
            }
            else {
                this.log.info('handling queued error: ', data.nextErrorId);
                if (!this.silent && data.resolved && this.currentMessage.spokenPromptOnResolution && this.currentMessage.spokenPromptOnResolution.length) {
                    jibo.tts.speak(
                        this.currentMessage.spokenPromptOnResolution, {
                            mode: jibo.tts.TTSMode.SSML
                        },
                        () => {
                            if (!this.skill) {
                                return;
                            }
                            this.cleanup();
                            this.removeAllThenDoError(data.nextErrorId);
                        }
                    );
                }
                else {
                    this.cleanup();
                    this.removeAllThenDoError(data.nextErrorId);
                }
            }
        }
        else {
            this.log.info('no more errors!');
            if (this.wifiSkill || this.wipeSkill) {
                this.log.info(`error display not doing anything because we're still doing wifi stuff`);

                // As they are no more errors, and we don't want to go back from
                // the wifi menu, from now on exit when touching head
                jibo.globalEvents.touchStop.on(this.onWifiExitedAfterSolved);
            }
            else {
                if (!this.silent && data && data.resolved && this.currentMessage.spokenPromptOnResolution && this.currentMessage.spokenPromptOnResolution.length) {
                    jibo.tts.speak(
                        this.currentMessage.spokenPromptOnResolution, {
                            mode: jibo.tts.TTSMode.SSML
                        },
                        () => {
                            if (!this.skill) {
                                return;
                            }
                            this.skill.exit2Idle();
                        }
                    );
                }
                else {
                    this.skill.exit2Idle();
                }
            }
        }
    }

    dismissError(): void {
        if (!this.skill) {
            return;
        }
        jibo.errors.processedError(this.errorCode, (err, data) => {
            if (!this.skill) {
                return;
            }
            if (err) {
                this.log.error(`error processing error ${this.errorCode}`, err, data);
            }
        });
    }

    onHeadUpdate(): void {
        //if any pads are touched
        if (jibo.system.padState.some((value) => value)) {
            if (!this.touchStartTime) {
                this.touchStartTime = Date.now();
            } else if (Date.now() - this.touchStartTime > 1000) {
                this.isHeadHeld = true;
            }
        } else if (this.touchStartTime) {
            this.isHeadHeld = false;
            this.touchStartTime = 0;
            this.numOfSwipes = 0;
        }
    }

    onSwipeUp(): void {
        if (!this.isHeadHeld || this.wipeSkill || this.wifiSkill) {
            return;
        }
        if (++this.numOfSwipes === SECRET_SWIPES_REQUIRED) {
            this.doWipeSkill();
        }
    }

    doWifi(): void {
        if (!this.skill) {
            return;
        }

        this.doPulse(false);
        this.log.info('launching WifiSkill as child of ErrorSkill');
        jibo.face.views.changeView({
                remove: true,
                leaveEmpty: true
            },
            () => {
                //this will launch WiFi Skill, bypassing Settings' internal skill switching mechanism
                //so we can maintain our uninterruptible status and easily return here after reconnecting to WiFi
                this.wifiSkill = new this.skill.SUB_SKILLZ.wifiStatus.Class(this.skill, 'wifiStatus', this.doneWifi.bind(this), false, true);
            }
        );
    }

    doneWifi(): void {
        if (!this.skill) {
            return;
        }
        this.log.info('done with ErrorSkill-initiated WifiSkill');
        this.doneOwnedSkill();
    }

    doneOwnedSkill(): void {
        //cancel any active counter of the secret wipe thing
        this.numOfSwipes = 0;
        this.touchStartTime = 0;

        if (this.queuedError) {
            this.cleanup();
            this.removeAllThenDoError(this.queuedError);
        }
        else {
            jibo.errors.getCurrentErrorId((err, errorCode)=>{
                if (errorCode) {
                    this.cleanup();
                    this.removeAllThenDoError(errorCode);
                }
                else {
                    this.skill.exit2Idle();
                }
            });
        }
    }

    onWifiExitedAfterSolved(): void {
        // Keep the behaviour consistent with a swipedown
        jibo.face.gestures.spoofGesture('swipedown');
    }

    doWipeSkill(): void {
        if (!this.skill) {
            return;
        }
        this.doPulse(false);
        this.log.info('launching WipeSkill as child of ErrorSkill');
        jibo.face.views.changeView({
                remove: true,
                leaveEmpty: true
            },
            () => {
                //this will launch WiFi Skill, bypassing Settings' internal skill switching mechanism
                //so we can maintain our uninterruptible status and easily return here after reconnecting to WiFi
                this.wipeSkill = new this.skill.SUB_SKILLZ.wipe.Class(this.skill, 'wipe', this.cancelledWipe.bind(this), true, true);
            }
        );
    }

    cancelledWipe(): void {
        if (!this.skill) {
            return;
        }
        this.log.info('done with ErrorSkill-initiated WipeSkill');
        this.doneOwnedSkill();
    }

    doWipe() {
        jibo.face.views.creator.registerClass(WipeView, 'WipeView');
        jibo.face.views.changeView(
            {
                remove: true,
                addView: 'assets/wipe/wipeView.json'
            },
            null, // onComplete
            null,  // onFailure
            (view: WipeView) => { // onLoaded
                view.setLogger(this.log);
                view.on('wipeFail', () => {
                    this.log.error('Wipe failed from Error Skill. This is probably real bad.');
                    jibo.systemManager.reboot((err) => {
                        if (this.skill && err) {
                            this.log.error('failed to reboot on wipe fail from error skill.', err);
                        }
                    });
                });
                view.run(true);
            }
        );
    }

    doPulse(doIt: boolean): void {
        if (doIt) {
            if (!this.doingPulse) {
                this.doingPulse = true;
                this.fadingUp = true;
                this.brightness = MIN_BRIGHTNESS;
                jibo.timer.on('update', this.ringPulse);
            }
        }
        else {
            jibo.timer.off('update', this.ringPulse);
            this.doingPulse = false;
            jibo.expression.setLEDColor([0, 0, 0]);
        }
    }

    ringPulse(elapsed: number): void {
        if (!this.skill) {
            // we should never ever get here, but if somehow this is running
            // after we've exited the error display, stop the pulse
            this.doPulse(false);
            return;
        }

        if (this.fadingUp) {
            this.brightness += (elapsed / 1000) * (1 / PULSE_LENGTH) * (MAX_BRIGHTNESS - MIN_BRIGHTNESS);
            if (this.brightness >= MAX_BRIGHTNESS) {
                this.brightness = MAX_BRIGHTNESS;
                this.fadingUp = false;
            }
        }
        else {
            this.brightness -= (elapsed / 1000) * (1 / PULSE_LENGTH) * (MAX_BRIGHTNESS - MIN_BRIGHTNESS);
            if (this.brightness <= MIN_BRIGHTNESS) {
                this.brightness = MIN_BRIGHTNESS;
                this.fadingUp = true;
            }
        }
        jibo.expression.setLEDColor([ERROR_COLOR[0] * this.brightness, ERROR_COLOR[1] * this.brightness, ERROR_COLOR[2] * this.brightness]);
    }

    removeAllThenDoError(nextError: string): void {
        jibo.face.views.changeView({
                removeAll: true,
                leaveEmpty: true
            },
            () => {
                this.doError(nextError);
            },
            () => {
                this.doError(nextError);
            }
        );
    }

    cleanup(): void {
        this.wifiSkill = null;
        this.wipeSkill = null;
        if (this.currentView && this.currentMessage && this.tapActions[this.currentMessage.tapAction]) {
            this.currentView.removeListener(TAP_EVENT, this.tapActions[this.currentMessage.tapAction]);
        }
        if (this.attentionHandler) {
            this.attentionHandler.release();
            this.attentionHandler = null;
        }
        jibo.tts.stop();
        this.doPulse(false);

        //remove callbacks for exit functions
        jibo.globalEvents.touchStop.removeListener(this.onWifiExitedAfterSolved);
    }

    destroy(): void {
        this.cleanup();
        this.brightness = null;
        this.skill = null;
        this.assetPack = null;
        this.currentView = null;
        this.errorCode = null;
        this.queuedError = null;
        jibo.timer.removeListener('update', this.onHeadUpdate);
    }
}

export default ErrorDisplay;
