import jibo = require('jibo');
import Settings from '../Settings';

import SubSkill from './SubSkill';
import BatteryView from '../views/BatteryView';

/**
 * Battery Skill - tell u how the battery doin'
 */
export default class BatterySkill extends SubSkill {

    private view: BatteryView;

    constructor(skill: Settings, intent: string, onClose: Function) {
        super(skill, intent, onClose);
        this.skill._analytics.batteryQuery();
        jibo.face.views.creator.registerClass(BatteryView, 'BatteryView');
        this.view = jibo.face.views.createView('BatteryView', 'assets/battery/batteryView.json', false) as BatteryView;
        this.view.assetPack = this.assetPack;
        this.view.once(jibo.face.views.CLOSED, this.destroyThenClose);
        jibo.face.views.changeView(
            {
                addView: this.view
            }
        );
    }

    stopAndDestroy(done: Function) {
        this.view.removeListener(jibo.face.views.CLOSED, this.destroyThenClose);
        jibo.face.views.changeView(
            { removeAll: true, leaveEmpty: true },
            () => {
                this.destroy();
                done();
            },
            () => {
                this.destroy();
                done('battery view close failed');
            }
        );
    }

    destroy() {
        jibo.face.views.creator.unregisterClass('BatteryView');
        this.view = null;
        super.destroy();
    }
}
