import jibo = require('jibo');
import Settings from '../Settings';

import SubSkill from './SubSkill';

/**
 * Updates Skill - Checkin' 4 updates
 */
export default class UpdatesSkill extends SubSkill {

    private flow: jibo.flow.FlowExecutor;

    constructor(skill: Settings, intent: string, onClose: Function) {
        super(skill, intent, onClose);

        if (jibo.face.views.currentView && jibo.face.views.currentView.id == 'eyeView') {
            this.startFlow();
        }
        else {
            jibo.face.views.createView('EyeView', null, true, () => { this.startFlow(); });
        }
    }

    startFlow() {
        this.flow = jibo.flow.run(
            require('../flows/Updates'), {
                enableLogging: true,
                params: {
                    log: this.log
                },
                assetPack: this.assetPack
            },
            (err, status) => {
                if (status != jibo.bt.Status.INTERRUPTED) {
                    jibo.face.views.changeView(
                        {
                            remove: true
                        },
                        () => {//onComplete
                            this.destroyThenClose();
                        },
                        () => {//onFail
                            this.destroyThenClose();
                        }
                    );
                };
            }
        );
    }

    stopAndDestroy(done: Function) {
        this.flow.stopAndDestroy().then(() => {
            this.destroy();
            if (jibo.face.views.currentView && jibo.face.views.currentView.id != 'eyeView') {
                jibo.face.views.changeView({
                    removeAll: true,
                    leaveEmpty: true
                },
                    () => {
                        done();
                    }, //onComplete
                    () => {
                        done();
                    } //onFail
                );
            }
            else {
                jibo.face.views.forceEyeView(
                    () => { done(); },
                    null,
                    null,
                    null,
                    () => { done(); }
                );
            }
        });
    }

    destroy() {
        this.flow.destroy();
        this.flow = null;
        super.destroy();
    }
}
