            this.currentView.qrNum = this.currentView.getComponentById('num') as jibo.face.views.Label;
            this.currentView.qrNum.text = `${this._getNextQRCodeNumber()}`;;
            this._startScanning();
            this.timeout = new TouchyTimeout(this.emitBack.bind(this), TIMEOUT_TIME);
